import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = ({ schedule, setSchedule }) => {
  const navigate = useNavigate();

  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [loading, setLoading] = useState(false);

  const generateSchedule = () => {
    if (!syllabus || !targetDate) {
      alert("Please enter both the syllabus and a target date!");
      return;
    }

    setLoading(true);

    setTimeout(() => {
      const topics = syllabus.split(',').map(item => item.trim());

      const generatedDays = topics.map((topic, index) => ({
        day: index + 1,
        topic: topic || `Topic ${index + 1}`,
        status: 'pending',
        date: new Date(Date.now() + index * 86400000).toLocaleDateString()
      }));

      setSchedule(generatedDays);
      setLoading(false);
    }, 1000);
  };

  const handleResetPlan = () => {
    if (window.confirm("Clear this plan and start a new one?")) {
      setSchedule(null);
    }
  };

  const completedCount = schedule
    ? schedule.filter(t => t.status === 'completed').length
    : 0;

  const progress = schedule
    ? (completedCount / schedule.length) * 100
    : 0;

  return (
    <div style={{ maxWidth: '800px', margin: '40px auto' }}>

      {!schedule ? (
        <div>
          <h2>Create Study Plan</h2>

          <input
            type="date"
            value={targetDate}
            onChange={(e) => setTargetDate(e.target.value)}
          />

          <textarea
            placeholder="Enter syllabus (comma separated)"
            value={syllabus}
            onChange={(e) => setSyllabus(e.target.value)}
          />

          <button onClick={generateSchedule}>
            {loading ? "Generating..." : "Generate Plan"}
          </button>
        </div>
      ) : (
        <>
          <h2>My Roadmap</h2>

          <div>
            <div style={{ width: `${progress}%`, height: '10px', background: 'green' }} />
            <p>{Math.round(progress)}%</p>
          </div>

          {schedule.map((item) => (
            <div
              key={item.day}
              onClick={() => navigate(`/study-session/${item.day}`)}
              style={{
                border: '1px solid gray',
                padding: '10px',
                margin: '10px',
                background: item.status === 'completed' ? 'lightgreen' : 'white'
              }}
            >
              <p>Day {item.day}</p>
              <p>{item.topic}</p>
            </div>
          ))}

          <button onClick={handleResetPlan}>
            Reset Plan
          </button>
        </>
      )}
    </div>
  );
};

export default Dashboard;
